// DATA RACE: unsynchronized shared mutable state.
// counter++ is a read-modify-write, not atomic.
public class Counter {
    private int count = 0;

    public void increment() {
        count++;              // load, add, store -- interleaves badly
    }

    public int get() {
        return count;         // may also read a stale value (visibility)
    }
}

// If 10 threads each call increment() 1_000_000 times,
// the final count is almost never 10_000_000.

// FIX 1: a mutex (intrinsic lock) makes the section atomic AND visible.
public class SafeCounter {
    private int count = 0;
    private final Object lock = new Object();

    public void increment() {
        synchronized (lock) { // mutual exclusion + happens-before edge
            count++;
        }
    }

    public int get() {
        synchronized (lock) {
            return count;
        }
    }
}

// FIX 2: a lock-free atomic using compare-and-swap under the hood.
import java.util.concurrent.atomic.AtomicInteger;

public class AtomicCounter {
    private final AtomicInteger count = new AtomicInteger(0);
    public void increment() { count.incrementAndGet(); } // CAS loop
    public int get() { return count.get(); }
}

// DEADLOCK: two threads acquire two locks in opposite orders.
Object lockA = new Object();
Object lockB = new Object();

// Thread 1
synchronized (lockA) {
    // ... work ...
    synchronized (lockB) { /* never reached if T2 holds lockB */ }
}

// Thread 2
synchronized (lockB) {
    // ... work ...
    synchronized (lockA) { /* never reached if T1 holds lockA */ }
}

