// async/await is promises in disguise: this function yields the
// event loop at each await, letting other work run meanwhile.
async function fetchUser(id) {
  const res = await fetch(`/users/${id}`); // suspends here
  const user = await res.json();           // and here
  return user;
}

package main

import (
	"fmt"
	"sync"
)

// Workers read jobs from `jobs` and write to `results`.
func worker(id int, jobs <-chan int, results chan<- int, wg *sync.WaitGroup) {
	defer wg.Done()
	for j := range jobs { // ranges until the channel is closed
		results <- j * j  // do the work; send result
	}
}

func main() {
	const numJobs = 9
	jobs := make(chan int, numJobs)
	results := make(chan int, numJobs)

	var wg sync.WaitGroup
	for w := 1; w <= 3; w++ { // fan-out to 3 workers
		wg.Add(1)
		go worker(w, jobs, results, &wg)
	}

	for j := 1; j <= numJobs; j++ {
		jobs <- j
	}
	close(jobs) // signal 'no more work'; workers' range loops end

	wg.Wait()      // wait for all workers to finish
	close(results) // now safe to close results

	sum := 0
	for r := range results { // fan-in
		sum += r
	}
	fmt.Println("sum of squares:", sum) // 285
}

import threading, time
from multiprocessing import Pool

def cpu_bound(n):
    total = 0
    for i in range(n):
        total += i * i
    return total

# THREADS: no speedup for CPU work -- the GIL serializes bytecode.
def with_threads():
    ts = [threading.Thread(target=cpu_bound, args=(10_000_000,)) for _ in range(4)]
    for t in ts: t.start()
    for t in ts: t.join()   # ~ same wall time as running them sequentially

# PROCESSES: real parallelism -- 4 interpreters, 4 GILs, 4 cores.
def with_processes():
    with Pool(4) as p:
        p.map(cpu_bound, [10_000_000] * 4)  # ~4x faster on 4 cores

# I/O-bound work DOES benefit from threads (GIL is released while waiting):
def fetch(url):
    time.sleep(1)   # simulate a network call; GIL is released during sleep
    return url

// BROKEN double-checked locking (pre-fix): instance may be seen
// non-null but not fully constructed by another thread.
public class Broken {
    private static Broken instance;                 // NOT volatile -- bug
    public static Broken get() {
        if (instance == null) {
            synchronized (Broken.class) {
                if (instance == null) instance = new Broken();
            }
        }
        return instance;
    }
}

// FIXED: 'volatile' establishes the happens-before edge so a reader
// that sees a non-null reference also sees a fully built object.
public class Fixed {
    private static volatile Fixed instance;
    public static Fixed get() {
        if (instance == null) {
            synchronized (Fixed.class) {
                if (instance == null) instance = new Fixed();
            }
        }
        return instance;
    }
}

