import java.util.concurrent.atomic.AtomicLong;

public class Counters {

    // --- Version A: mutex / intrinsic lock ---
    static final class LockedCounter {
        private long count = 0;
        private final Object lock = new Object();

        void increment() {
            synchronized (lock) {   // mutual exclusion + happens-before
                count++;
            }
        }
        long get() {
            synchronized (lock) {   // read under lock for visibility too
                return count;
            }
        }
    }

    // --- Version B: lock-free atomic (CAS) ---
    static final class AtomicCounter {
        private final AtomicLong count = new AtomicLong(0);
        void increment() { count.incrementAndGet(); } // internal CAS loop
        long get()       { return count.get(); }
    }

    public static void main(String[] args) throws InterruptedException {
        LockedCounter locked = new LockedCounter();
        AtomicCounter atomic = new AtomicCounter();

        final int threads = 10, perThread = 1_000_000;
        Runnable jobLocked = () -> { for (int i = 0; i < perThread; i++) locked.increment(); };
        Runnable jobAtomic = () -> { for (int i = 0; i < perThread; i++) atomic.increment(); };

        Thread[] ts = new Thread[threads * 2];
        for (int i = 0; i < threads; i++)      ts[i] = new Thread(jobLocked);
        for (int i = 0; i < threads; i++)      ts[threads + i] = new Thread(jobAtomic);
        for (Thread t : ts) t.start();
        for (Thread t : ts) t.join();

        long expected = (long) threads * perThread;
        System.out.println("locked = " + locked.get() + " (expected " + expected + ")");
        System.out.println("atomic = " + atomic.get() + " (expected " + expected + ")");
    }
}

package main

import (
	"fmt"
	"sync"
	"sync/atomic"
)

func main() {
	const (
		bufferSize   = 4  // bounded buffer -> backpressure
		numProducers = 3
		numConsumers = 2
		itemsEach    = 5
	)

	items := make(chan int, bufferSize) // full channel blocks producers
	var produced, consumed int64

	// --- Producers ---
	var pwg sync.WaitGroup
	for p := 0; p < numProducers; p++ {
		pwg.Add(1)
		go func(id int) {
			defer pwg.Done()
			for i := 0; i < itemsEach; i++ {
				items <- id*100 + i // blocks here when buffer is full
				atomic.AddInt64(&produced, 1)
			}
		}(p)
	}

	// Close the channel once all producers finish (sender closes, once).
	go func() {
		pwg.Wait()
		close(items)
	}()

	// --- Consumers (fan-out) ---
	var cwg sync.WaitGroup
	for c := 0; c < numConsumers; c++ {
		cwg.Add(1)
		go func(id int) {
			defer cwg.Done()
			for v := range items { // exits when closed AND drained
				_ = v // process the item
				atomic.AddInt64(&consumed, 1)
			}
		}(c)
	}

	cwg.Wait() // all items consumed, all consumers returned

	fmt.Printf("produced=%d consumed=%d (expected %d)\n",
		produced, consumed, numProducers*itemsEach)
}
